sys_script_include.script:
var AROPAdminAjax = Class.create();
AROPAdminAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    rebuildLibraries: function() {
        var MODULES = [
            'ITSM', 'ITOM', 'CMDB', 'HRSD',
            'CSM', 'FIELD_SERVICE', 'AIOPS', 'GRC', 'SPM',
            'PLATFORM', 'VIRTUAL_AGENT', 'DEX', 'SECOPS',
            'HS', 'OTSM', 'CREATOR', 'SPO', 'TPRM', 'LSD', 'WSD', 'HAM', 'SAM'
        ];
        var totalInjected = 0;
        var totalSkipped  = 0;
        var errors = [];
        for (var m = 0; m < MODULES.length; m++) {
            var module  = MODULES[m];
            var libName = 'AROPCheckLibrary_' + module;
            var libHeader =
                'var ' + libName + ' = Class.create();\n' +
                libName + '.prototype = {\n' +
                '    initialize: function() {},\n' +
                '    _count: function(table, query) { var gr = new GlideRecord(table); if (query) gr.addEncodedQuery(query); gr.query(); return gr.getRowCount(); },\n' +
                '    _pct: function(num, den) { return den > 0 ? Math.round((num/den)*100) : 0; },\n';
            var libFooter = '    type: \'' + libName + '\'\n};';
            var checks = new GlideRecord('x_snc_airop_check_definition');
            checks.addQuery('module', module);
            checks.addQuery('is_active', true);
            checks.orderBy('order');
            checks.query();
            var methodBlocks = [];
            var injected = 0;
            var skipped = 0;
            while (checks.next()) {
                var checkNumber = checks.getValue('number');
                var isManual = checks.getValue('is_manual');
                var checkScript = checks.getValue('check_script');
                if (!checkNumber) { skipped++; continue; }
                var method;
                if (isManual == true || isManual == '1') {
                    method =
                        '    ' + checkNumber + ': function() {\n' +
                        '        return { status: \'needs_validation\', actualValue: \'\', finding: \'\' };\n' +
                        '    }';
                } else {
                    if (!checkScript || checkScript.trim() === '') { skipped++; continue; }
                    var trimmed = checkScript.trim();
                    var alreadyCalled = trimmed.endsWith('})()')
                                     || trimmed.endsWith('})();');
                    var returnStatement = alreadyCalled
                        ? 'return ' + trimmed + (trimmed.endsWith(';') ? '' : ';')
                        : 'return (' + trimmed + ')();';
                    method =
                        '    ' + checkNumber + ': function() {\n' +
                        '        try {\n' +
                        '            ' + returnStatement + '\n' +
                        '        } catch(e) {\n' +
                        '            return { status: \'needs_validation\', actualValue: \'Script error: \' + e.message, finding: \'Error in ' + checkNumber + ': \' + e.message };\n' +
                        '        }\n' +
                        '    }';
                }
                methodBlocks.push(method);
                injected++;
            }
            var newLibScript = libHeader +
                               (methodBlocks.length > 0 ? methodBlocks.join(',\n') + ',\n' : '') +
                               libFooter;
            var libGR = new GlideRecord('sys_script_include');
            libGR.addQuery('name', libName);
            libGR.setLimit(1);
            libGR.query();
            if (libGR.next()) {
                libGR.setValue('script', newLibScript);
                libGR.setValue('access', 'public');
                libGR.setWorkflow(false);
                libGR.update();
                totalInjected += injected;
                totalSkipped  += skipped;
            } else {
                errors.push(libName);
            }
        }
        var result = {
            success: errors.length === 0,
            injected: totalInjected,
            skipped: totalSkipped,
            errors: errors.join(', ')
        };
        this.setAnswer(JSON.stringify(result));
    },

    loadDefaultDefinitions: function() {
        try {
            var seeder = new AROPCheckSeeder();
            var seedResult = seeder.seed();

            // Rebuild all libraries after seeding
            this.rebuildLibraries();

            var result = {
                success: seedResult.failed === 0,
                inserted: seedResult.inserted,
                failed: seedResult.failed,
                total: seedResult.total
            };
            this.setAnswer(JSON.stringify(result));
        } catch(e) {
            this.setAnswer(JSON.stringify({
                success: false,
                error: e.message
            }));
        }
    },

    type: 'AROPAdminAjax'
});
